import React, { useState, useEffect } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { auth } from './firebase/config';
const PlatformShell = React.lazy(() => import('./components/PlatformShell'));
import Login from './components/Login';
import { BusinessProvider } from './BusinessContext';
import { initRegistry } from './registry_init';
import { httpsCallable, getFunctions } from 'firebase/functions';
import { ToastProvider, useToast } from './components/ToastProvider';
import { useStore } from './store';
import { UserService } from './services/user.service';
import { FirestoreService } from './services/firestore.service';
import ErrorBoundary from './components/ErrorBoundary';
import './index.css';

const AuthObserver = () => {
  const { addToast } = useToast();

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code) {
      // ── [SECURITY FIX V-07] Validation du state CSRF ──────────────────────
      const expectedState = sessionStorage.getItem('oauth_state');
      const receivedState = urlParams.get('state');
      sessionStorage.removeItem('oauth_state');

      if (!expectedState || expectedState !== receivedState) {
        console.error('[OAuth] CSRF détecté ou state manquant. Callback rejeté.');
        addToast('Connexion refusée : anomalie de sécurité détectée.', 'error');
        window.history.replaceState({}, document.title, '/');
        return;
      }

      const handleCallback = async () => {
        try {
          const functions = getFunctions();
          const exchangeFunc = httpsCallable(functions, 'exchangeSocialToken');
          const result = await exchangeFunc({ provider: 'facebook', code, redirectUri: window.location.origin + '/' });
          const { accessToken } = result.data;
          await FirestoreService.setDocument('marketing', 'accounts_live', {
            facebook: { accessToken, statut: 'Connecté', derniereSynchro: new Date().toISOString() }
          }, true);
          window.history.replaceState({}, document.title, "/");
          addToast("Compte Marketing connecté avec succès !", 'success');
        } catch (error) {
          console.error("Erreur exchange token:", error);
          addToast("Échec de la connexion API. Vérifiez vos accès.", 'error');
        }
      };
      handleCallback();
    }
  }, [addToast]);

  return null;
};

function App() {
  const [view, setView] = useState('login');
  const [isInitializing, setIsInitializing] = useState(true);
  const _hasHydrated = useStore(state => state._hasHydrated);
  const globalSettings = useStore(state => state.globalSettings);

  useEffect(() => {
    initRegistry();
  }, []);

  const theme = 'light';

  useEffect(() => {
    const setUser = useStore.getState().setUser;

    // Safety fallback: If Firebase doesn't respond in 5s, we force initialization
    const fallbackTimer = setTimeout(() => {
      if (isInitializing) {
        console.warn('Firebase Auth took too long to respond. Forcing initialization.');
        setIsInitializing(false);
      }
    }, 5000);

    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      clearTimeout(fallbackTimer);
      if (firebaseUser) {
        try {
          const userProfile = await UserService.syncProfile(firebaseUser);
          setUser(userProfile);

          // Initialize Realtime Presence
          import('./services/presence.service').then(({ PresenceService }) => {
            PresenceService.setPresence(firebaseUser.uid);
          });

          setView('dashboard');
        } catch (error) {
          console.error("[App] Erreur sync profil:", error);
          // Fallback minimal — rôle depuis Custom Claims (token signé, non modifiable côté client)
          try {
            const tokenResult = await firebaseUser.getIdTokenResult();
            const claimedRole = tokenResult.claims?.role || 'GUEST';
            setUser({
              id: firebaseUser.uid,
              email: firebaseUser.email,
              nom: firebaseUser.displayName || 'Utilisateur',
              role: claimedRole,
            });
            setView(claimedRole !== 'GUEST' ? 'dashboard' : 'login');
          } catch {
            setView('login');
          }
        }
      } else {
        setView('login');
      }
      setIsInitializing(false);
    });
    return () => {
      unsubscribe();
      clearTimeout(fallbackTimer);
    };
  }, []);
  if (isInitializing || !_hasHydrated) {
    return <InitializingView label={isInitializing ? "Vérification de la session..." : "Chargement du profil..."} />;
  }

  return (
    <ErrorBoundary>
      <BusinessProvider>
        <ToastProvider>
          <AuthObserver />
          <div className="app-container">
            {view === 'login' ? <Login onLogin={() => setView('dashboard')} /> : (
              <React.Suspense fallback={<InitializingView label="Chargement du Noyau..." />}>
                <PlatformShell theme={theme} setView={setView} />
              </React.Suspense>
            )}
          </div>
        </ToastProvider>
      </BusinessProvider>
    </ErrorBoundary>
  );
}

const InitializingView = ({ label = "Initialisation du noyau..." }) => (
  <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', background: 'var(--bg)', color: 'var(--text)' }}>
    <div className="spinner" style={{ width: '50px', height: '50px', border: '4px solid var(--bg-subtle)', borderTop: '4px solid var(--accent)', borderRadius: '50%', marginBottom: '1.5rem' }} />
    <div style={{ fontSize: '1.25rem', fontWeight: 700, letterSpacing: '2px', opacity: 0.8 }}>IPC INTELLIGENCE</div>
    <div style={{ fontSize: '0.875rem', color: 'var(--text-muted)', marginTop: '0.5rem' }}>{label}</div>
    <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } } .spinner { animation: spin 1s linear infinite; }`}</style>
  </div>
);

export default App;

/* ══════════════════════════════════════════════════════════════════════════
   🚀 IPC ORCHESTRATOR: REAL-TIME DATA & ENGINE
   ══════════════════════════════════════════════════════════════════════════ */

import React, { useEffect, useRef, useCallback } from 'react';
import { auth } from './firebase/config';
import { useStore } from './store';
import { nexusWorkflowEngine } from './services/WorkflowEngine';
import { CallListener } from './services/CallListener';
import { UserService } from './services/user.service';
import { FirestoreService } from './services/firestore.service';
import { logger } from './utils/logger';

/**
 * BusinessProvider (Passive Orchestrator)
 * 
 * DESIGN: Stable real-time synchronization.
 * We use useStore.getState() inside listeners to avoid dependency loops.
 */
export const BusinessProvider = ({ children }) => {
  const dataStagingRef = useRef({});
  const batchUpdateTimerRef = useRef(null);

  const user = useStore(s => s.user);
  const setUser = useStore(s => s.setUser);
  const userId = user?.id;

  // 1. Batched Sync Engine (memoized but stable)
  const applyBatchedUpdates = useCallback(() => {
    useStore.getState().setData(prev => {
      const newState = { ...prev };
      let changed = false;

      Object.entries(dataStagingRef.current).forEach(([colName, docs]) => {
        if (['workflows', 'notifications', 'users'].includes(colName)) return;

        const grouped = {};
        docs.forEach(d => {
          const sub = d.subModule || 'others';
          if (!grouped[sub]) grouped[sub] = [];
          grouped[sub].push(d);
        });

        // [AUDIT] Sécurité: Garantir que les propriétés essentielles (orders, products, etc.) existent toujours
        const initialModuleState = {
          sales: { orders: [], invoices: [] },
          inventory: { products: [], movements: [] },
          production: { orders: [], boms: [], machines: [], workOrders: [] },
          finance: { entries: [], lines: [], invoices: [], vendor_bills: [] },
          website: { config: {}, chats: [] },
          signature: { requests: [] }
        }[colName] || {};

        const currentModuleState = newState[colName] || initialModuleState;
        const updatedModuleState = { ...initialModuleState, ...grouped };

        // Optimization: Shallow compare submodule keys to avoid unnecessary re-renders
        let moduleChanged = false;
        const keys = Object.keys(updatedModuleState);
        for (const key of keys) {
          if (currentModuleState[key] !== updatedModuleState[key]) {
            moduleChanged = true;
            break;
          }
        }

        if (moduleChanged) {
          newState[colName] = updatedModuleState;
          changed = true;
        }
      });

      return changed ? newState : prev;
    });
  }, []);

  const scheduleUpdate = useCallback((colName, docs) => {
    dataStagingRef.current[colName] = docs;
    if (batchUpdateTimerRef.current) return;

    batchUpdateTimerRef.current = setTimeout(() => {
      batchUpdateTimerRef.current = null;
      applyBatchedUpdates();
    }, 150);
  }, [applyBatchedUpdates]);

  // 2. Real-time Listeners (Separated & Atomic)
  useEffect(() => {
    if (!auth.currentUser || !userId) return;

    // Initialize Workflow Engine
    nexusWorkflowEngine.init();

    // A. Business Modules Sync — [SOFT-DELETE ENABLED] via FirestoreService
    const collections_to_sync = [
      'crm', 'sales', 'inventory', 'production', 'purchase',
      'accounting', 'finance', 'hr', 'base', 'activities', 'legal', 'signature', 'documents'
    ];

    const unsubscribes = collections_to_sync.map(colName => {
      return FirestoreService.subscribeToCollection(
        colName, 
        { orderByField: '_createdAt', descending: true, limitTo: 300 },
        (docs) => scheduleUpdate(colName, docs),
        (err) => logger.error(`[BusinessContext] Sync failed for ${colName}`, err)
      );
    });

    // B. BPM Workflows
    const unsubWorkflows = FirestoreService.subscribeToCollection('workflows', {}, (wfs) => {
      useStore.getState().setWorkflows(wfs);
    });

    // C. Global Notifications
    const unsubNotify = FirestoreService.subscribeToCollection(
      'notifications', 
      { orderByField: '_createdAt', descending: true, limitTo: 100 },
      (ns) => useStore.getState().setNotifications(ns)
    );

    // D. User Permissions
    const unsubUsers = FirestoreService.subscribeToCollection('users', {}, (users) => {
      const currentUserProfile = users.find(u => u.id === userId);
      if (currentUserProfile) {
        useStore.getState().setPermissions(currentUserProfile.permissions || {});

        // --- IDENTITY BRIDGE (STABLE OVERRIDE) ---
        // WHY: Empêche Firestore de "rétrograder" le rôle du créateur après la synchro initiale.
        let finalRole = currentUserProfile.role || 'STAFF';
        const currentEmail = useStore.getState().user?.email;
        const isCreator = currentEmail?.toLowerCase() === 'fall.jcjunior@gmail.com';

        if (isCreator) {
          finalRole = 'SUPER_ADMIN';
        }

        if (finalRole !== useStore.getState().userRole) {
           useStore.getState().setUserRole(finalRole);
        }
      }
    });

    // E. Call Listener (Decoupled Service)
    CallListener.init(userId);

    // F. Global Settings (Hub de Configuration)
    const unsubSettings = FirestoreService.subscribeToCollection('settings', {}, (settingsDocs) => {
      const coreSettings = settingsDocs.find(d => d.id === 'core') || {};
      useStore.getState().setConfig(prev => ({ ...prev, ...coreSettings }));
    });

    // 0. Auth Identity Bridge — rôle lu depuis Firestore via UserService
    const unsubAuth = auth.onAuthStateChanged(async fbUser => {
      if (fbUser) {
        try {
          const userProfile = await UserService.syncProfile(fbUser);
          setUser(userProfile);
          logger.info('[BusinessContext] Profil synchronisé', { uid: fbUser.uid, role: userProfile.role });
        } catch (err) {
          logger.error('[BusinessContext] Erreur sync profil', err);
          // Fallback minimal si Firestore indisponible
          setUser({
            id: fbUser.uid,
            email: fbUser.email,
            nom: fbUser.displayName || 'Utilisateur',
            role: 'STAFF'
          });
        }
      } else {
        setUser({ id: 'guest', nom: 'Utilisateur', email: '', role: 'GUEST' });
      }
    });

    return () => {
      unsubAuth();
      unsubscribes.forEach(unsub => unsub());
      unsubWorkflows();
      unsubNotify();
      unsubUsers();
      if (unsubSettings) unsubSettings();
      CallListener.stop();
    };
  }, [userId, scheduleUpdate]); // Minimum dependencies

  return <>{children}</>;
};

